var e=[{id:`L2_1`,type:`dialog`,speaker:`GENERAL_NPC_NOA_NULL`,text:{KOREA:`전군. 타깃을 생포해라. 방해꾼은 전부 사살해도 좋다.`,JPN:`全軍。ターゲットを生け捕りにしろ。邪魔者は全員射殺して構わない。`,ENG:`All hands, capture the target alive. Do as you please with the others.`,TWN:`全員注意，要生擒目標，妨礙者一律殺無赦。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`나타났군요. 당주님의 말씀대로입니다.`,JPN:`現れましたね。当主の言葉どおりです。`,ENG:`They are here. Just like Lady Nanahara said they would.`,TWN:`來了，果真如堂主所言。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`상처를 생각해서 되도록 전면전은 피하세요, 치후유.`,JPN:`傷のことを考えてなるべく全面戦争は避けてください、千冬。`,ENG:`Chifuyu, be mindful of your wound and try to avoid facing them head on as much as possible.`,TWN:`千冬，你的傷還沒好，要盡量避免正面交鋒。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`……알겠습니다.`,JPN:`……承知しました。`,ENG:`...Understood.`,TWN:`……是，遵命。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`GENERAL_NPC_NOA_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};